    seo: { title: `Sensitive Skin: What's Actually Causing It and How to Calm It Down`, description: `Reactive skin has real, understandable causes — disrupted pH, barrier damage, and ingredient overload. Here's how to identify your triggers and build a calming routine that actually works.` },
    blogHandle: 'news',
